package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithAllowMissingColumnNames() {
        // Create a mock CSVFormat object
        CSVFormat csvFormatMock = mock(CSVFormat.class);

        // Set the expected value for allowMissingColumnNames
        boolean expectedAllowMissingColumnNames = true;

        // Call the method withAllowMissingColumnNames on the mock object
        CSVFormat result = csvFormatMock.withAllowMissingColumnNames(expectedAllowMissingColumnNames);

        // Assert that the returned CSVFormat object has the correct allowMissingColumnNames value
        assertEquals(expectedAllowMissingColumnNames, result.getAllowMissingColumnNames());
    }
}
